page.script:
document.getElementById('signupForm').addEventListener('submit', async function(e) {
  e.preventDefault();
  const username = document.querySelector('field[name="username"]').value;
  const password = document.querySelector('field[name="password"]').value;
  const confirmPassword = document.querySelector('field[name="confirmPassword"]').value;
  if (password !== confirmPassword) {
    alert('Passwords do not match');
    return;
  }
  const response = await fetch('/auth/register', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ username, password })
  });
  const result = await response.json();
  if (result.status === 'success') {
    window.location.href = '/signin';
  } else {
    alert(result.message);
  }
});
